import { useState } from "react";
import "./style.css";

function App() {
  const [images, setImages] = useState([
    {
      id: 1,
      title: "Mountain Escape",
      category: "Nature",
      url: "https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=400"
    },

    {
      id: 2,
      title: "City Lights",
      category: "Travel",
      url: "https://images.unsplash.com/photo-1494526585095-c41746248156?w=400"
    },

    {
      id: 3,
      title: "Ocean Breeze",
      category: "Beach",
      url: "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=400"
    }
  ]);

  const [title, setTitle] = useState("");
  const [category, setCategory] = useState("");
  const [url, setUrl] = useState("");

  // Add Image

  const addImage = () => {
    if (title && category && url) {
      const newImage = {
        id: Date.now(),
        title,
        category,
        url
      };

      setImages([...images, newImage]);

      setTitle("");
      setCategory("");
      setUrl("");
    }
  };

  // Delete Image

  const deleteImage = (id) => {
    const updatedImages = images.filter(
      (item) => item.id !== id
    );

    setImages(updatedImages);
  };

  return (
    <div className="container">
      <h1 className="title">
        Dynamic Image Gallery
      </h1>

      {/* Input Section */}

      <div className="input-section">
        <input
          type="text"
          placeholder="Image Title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />

        <input
          type="text"
          placeholder="Category"
          value={category}
          onChange={(e) => setCategory(e.target.value)}
        />

        <input
          type="text"
          placeholder="Image URL"
          value={url}
          onChange={(e) => setUrl(e.target.value)}
        />

        <button onClick={addImage}>
          Add Image
        </button>
      </div>

      {/* Gallery */}

      <div className="gallery">
        {images.map((item) => (
          <div className="card" key={item.id}>
            <img
              src={item.url}
              alt={item.title}
            />

            <div className="card-content">
              <h3>{item.title}</h3>

              <p>{item.category}</p>

              <button
                className="delete-btn"
                onClick={() =>
                  deleteImage(item.id)
                }
              >
                Delete
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
